<template><el-card><template #header>技能库</template><PageToolbar><el-input v-model="q" placeholder="搜索技能"/><template #actions><el-button type="primary">新建技能</el-button></template></PageToolbar><DataTable :data="filtered"><el-table-column prop="name" label="技能名称" min-width="190"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="intent" label="触发意图"/><el-table-column prop="knowledge" label="关联知识"/><el-table-column prop="rules" label="关联规则"/><el-table-column prop="tools" label="关联工具"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column prop="version" label="版本"/><el-table-column prop="calls" label="调用次数"/><el-table-column prop="successRate" label="成功率"/><el-table-column label="操作" width="220"><template #default="s"><el-button link>编辑</el-button><el-button link type="warning" @click="s.row.status='reviewing'">提交审核</el-button><el-button link type="success" @click="s.row.status='published'">发布</el-button></template></el-table-column></DataTable></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { skills } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; import PageToolbar from '@/components/PageToolbar.vue'; import StatusTag from '@/components/StatusTag.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(skills))); const q=ref(''); const filtered=computed(()=>rows.value.filter(i=>!q.value||JSON.stringify(i).includes(q.value)));</script>
